from __future__ import annotations


def management_report_dashboard_html() -> str:
    return r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Отчёт для руководства — AI-BIT</title><style>
:root{color-scheme:dark;--bg:#07101d;--panel:#101b2d;--line:#283956;--text:#eef5ff;--muted:#91a3bd;--accent:#6d8cff;--ok:#35d08a;--warn:#ffbd4a;--bad:#ff5d78}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 80% 0,rgba(109,140,255,.14),transparent 30%),var(--bg);color:var(--text);font:14px/1.5 Inter,Segoe UI,Arial,sans-serif}main{max-width:1260px;margin:auto;padding:24px 28px 80px}.hero{display:flex;justify-content:space-between;gap:18px;align-items:flex-start;margin-bottom:18px}.hero h1{margin:0;font-size:29px}.hero p,.muted{color:var(--muted)}.actions{display:flex;gap:8px;flex-wrap:wrap}.btn,button{border:1px solid var(--line);background:var(--panel);color:var(--text);padding:9px 12px;border-radius:10px;text-decoration:none;cursor:pointer}.primary{background:linear-gradient(135deg,#496ee8,#7657de);border:0}.grid{display:grid;grid-template-columns:1.35fr repeat(4,1fr);gap:12px}.card,.section{background:linear-gradient(180deg,rgba(20,34,56,.97),rgba(12,23,39,.97));border:1px solid var(--line);border-radius:15px;padding:18px}.section{margin-top:14px}.score{font-size:50px;font-weight:850;line-height:1}.value{font-size:27px;font-weight:800;margin:5px 0}.label{font-size:12px;color:var(--muted)}.ok{color:var(--ok)}.warn{color:var(--warn)}.bad{color:var(--bad)}.summary-text{font-size:16px;line-height:1.7}.decision{padding:13px;border-radius:11px;background:rgba(109,140,255,.09);border:1px solid rgba(109,140,255,.28);margin:9px 0}.links{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.link-card{display:block;padding:16px;border:1px solid var(--line);border-radius:13px;background:rgba(16,27,45,.8);color:var(--text);text-decoration:none}.link-card:hover{border-color:var(--accent);transform:translateY(-1px)}details{margin-top:14px;border:1px solid var(--line);border-radius:14px;padding:14px;background:rgba(16,27,45,.72)}summary{cursor:pointer;font-weight:750}.row{display:grid;grid-template-columns:1fr auto;gap:10px;padding:10px 0;border-bottom:1px solid rgba(40,57,86,.65)}.row:last-child{border:0}.empty{color:var(--muted);padding:18px}@media(max-width:1050px){.grid{grid-template-columns:repeat(2,1fr)}.links{grid-template-columns:repeat(2,1fr)}}@media(max-width:650px){main{padding:18px}.hero{display:block}.grid,.links{grid-template-columns:1fr}}
</style></head><body><main><div class="hero"><div><h1>Отчёт для руководства</h1><p>Краткий управленческий вывод за 30 секунд. Детальная аналитика вынесена в специализированные разделы.</p><div id="updated" class="muted">Загрузка последнего подтверждённого снимка…</div></div><div class="actions"><button id="refresh" class="primary">Обновить данные</button><a class="btn" href="/about">О системе</a></div></div><div id="content"><div class="section empty">Формируется управленческая сводка…</div></div><details><summary>Подробный отчёт и история PDF</summary><div class="actions" style="margin-top:14px"><button id="generate">Сформировать подробный PDF</button><a class="btn" href="/management-reports">История отчётов</a></div><div id="reportStatus" class="muted" style="margin-top:10px"></div></details></main><script>
const $=s=>document.querySelector(s);const esc=v=>{const d=document.createElement('div');d.textContent=v??'';return d.innerHTML};const num=v=>new Intl.NumberFormat('ru-RU',{maximumFractionDigits:1}).format(Number(v||0));const money=v=>new Intl.NumberFormat('ru-RU').format(Math.round(Number(v||0)))+' ₸';const cls=v=>Number(v)>=75?'ok':Number(v)>=55?'warn':'bad';
function conclusionText(d){const c=d.management_conclusion||{};if(c.executive_summary)return c.executive_summary;if(c.summary)return c.summary;const s=d.source_summary||{},m=d.digital_maturity||{};return 'Система используется в рабочем режиме. Общая оценка составляет '+num(m.score)+' из 100. Просрочка открытых задач — '+num(s.overdue_rate)+'%, задач без срока — '+(s.without_deadline||0)+'. Основной управленческий приоритет — усилить контроль исполнения и завершить внедрение ключевых цифровых процессов.'}
function nextAction(d){const c=d.ai_cio||{},r=(c.recommendations||[])[0];if(r)return r.title;const roots=((d.executive_kpi||{}).root_causes||[])[0];return roots?.recommended_action||'Утвердить ответственных и сроки по ключевым направлениям внедрения.'}
function render(d){const m=d.digital_maturity||{},s=d.source_summary||{},bv=((d.business_value||{}).total)||{},k=d.executive_kpi||{},roots=(k.root_causes||[]).slice(0,3),risks=(d.risks||[]).slice(0,3);const critical=risks.filter(x=>x.severity==='critical'||x.severity==='high').length;const html='<div class="grid"><div class="card"><div class="label">Общая оценка внедрения</div><div class="score '+cls(m.score)+'">'+esc(num(m.score))+'</div><div class="muted">из 100 · '+esc(m.level||'')+'</div></div><div class="card"><div class="label">Критичных проблем</div><div class="value bad">'+esc(critical)+'</div></div><div class="card"><div class="label">Просрочка</div><div class="value bad">'+esc(num(s.overdue_rate))+'%</div></div><div class="card"><div class="label">Без срока</div><div class="value warn">'+esc(s.without_deadline||0)+'</div></div><div class="card"><div class="label">Потенциальный эффект</div><div class="value ok" style="font-size:20px">'+esc(money(bv.annual_saving_kzt))+'</div><div class="muted">в год</div></div></div><section class="section"><h2>Управленческий вывод</h2><div class="summary-text">'+esc(conclusionText(d))+'</div><div class="decision"><b>Следующее действие</b><div>'+esc(nextAction(d))+'</div></div></section><section class="section"><h2>Детальная аналитика</h2><div class="links"><a class="link-card" href="/digital-passport"><b>Цифровой паспорт</b><br><span class="muted">Зрелость всех направлений на одном экране</span></a><a class="link-card" href="/process-optimizer"><b>Оптимизация процессов</b><br><span class="muted">Рейтинг процессов и узкие места</span></a><a class="link-card" href="/ai-cio"><b>AI CIO</b><br><span class="muted">Приоритетные решения на 90 дней</span></a><a class="link-card" href="/transformation-roadmap"><b>Дорожная карта</b><br><span class="muted">Этапы, сроки и ответственные</span></a><a class="link-card" href="/risk-forecast"><b>Прогноз рисков</b><br><span class="muted">Динамика и ожидаемые отклонения</span></a><a class="link-card" href="/business-value"><b>Бизнес-эффект</b><br><span class="muted">Экономия времени и денег</span></a></div></section><details><summary>Почему система сделала такой вывод</summary><section class="section">'+(roots.length?roots.map(x=>'<div class="row"><div><b>'+esc(x.title||x.fact||'Отклонение')+'</b><div class="muted">'+esc(x.root_cause||x.business_impact||'')+'</div></div><span>'+esc(x.confidence||0)+'%</span></div>').join(''):'<div class="empty">Подтверждённые корневые причины не сформированы.</div>')+'</section></details>';$('#content').innerHTML=html;$('#updated').textContent='Данные обновлены: '+new Date(d.generated_at).toLocaleString('ru-RU')}
async function latest(){const r=await fetch('/executive-intelligence/latest');const d=await r.json();if(!r.ok)throw new Error(d.detail||'Ошибка загрузки');render(d)}async function refresh(){try{$('#updated').textContent='Выполняется обновление…';const r=await fetch('/executive-intelligence/collect',{method:'POST'});const d=await r.json();if(!r.ok)throw new Error(d.detail||'Ошибка обновления');render(d)}catch(e){$('#updated').textContent='Не удалось обновить данные. Показан последний снимок.';try{await latest()}catch(_){$('#content').innerHTML='<div class="section bad">'+esc(e.message)+'</div>'}}}$('#refresh').onclick=refresh;$('#generate').onclick=async()=>{try{$('#generate').disabled=true;$('#reportStatus').textContent='Формируется подробный PDF…';const r=await fetch('/management-reports/generate?mode=detailed',{method:'POST'});const d=await r.json();if(!r.ok)throw new Error(d.detail||'Ошибка');$('#reportStatus').innerHTML='Отчёт готов: <a href="/management-reports/'+esc(d.id)+'/pdf" target="_blank">открыть PDF</a>'}catch(e){$('#reportStatus').textContent='Ошибка: '+e.message}finally{$('#generate').disabled=false}};latest().catch(()=>refresh());
</script></body></html>'''
